# Skeptic re-check — instruction vs starter defect
from collections import defaultdict, deque
adj = defaultdict(set)
for u, v in [('A','B'),('B','C'),('C','D')]:
    adj[u].add(v); adj[v].add(u)
q = deque([('A', ['A'])]); seen = {'A'}
path = None
while q:
    n, p = q.popleft()
    if n == 'D':
        path = p; break
    for m in sorted(adj[n]):
        if m not in seen:
            seen.add(m); q.append((m, p+[m]))
print("path", path)
print("hops", len(path)-1)
print("found", path is not None)

# Skeptic re-check — instruction vs starter defect
from collections import defaultdict
edges=[('A','B'),('B','C'),('C','D')]
adj=defaultdict(set)
for u,v in edges:
    adj[u].add(v); adj[v].add(u)

def ego(seed, k):
    seen={seed}; layer={seed}
    for _ in range(k):
        nxt=set()
        for n in layer:
            for m in adj[n]:
                if m not in seen:
                    seen.add(m); nxt.add(m)
        layer=nxt
    return seen
print("k1", sorted(ego("A",1)))
print("k2", sorted(ego('A',2)))
print("has_D_k2", 'D' in ego('A',2))
